#include <iostream>
#include <iomanip>
using namespace std;

int main() {
 int num = 255;
 double pi = 3.14159265;

 // Base conversion
 cout << "Decimal: " << dec << num << endl;
 cout << "Octal: " << oct << num << endl;
 cout << "Hexadecimal: " << hex << showbase << num << endl;

 // Reset and show floating point
 cout << dec << fixed << setprecision(2);
 cout << "Pi: " << pi << endl;

 // Scientific notation
 cout << scientific << pi << endl;

 // Field width and fill
 cout << setfill('*') << setw(10) << 42 << endl;

 return 0;
}

#include <iostream>
#include <iomanip>
#include <string>
using namespace std;

int main() {
 cout << setfill('=') << setw(30) << "" << endl;
 cout << setfill(' ') << " STUDENT MARKS TABLE" << endl;
 cout << setfill('=') << setw(30) << "" << endl;

 // Header
 cout << setfill(' ') << left 
 << setw(10) << "Roll No" 
 << setw(15) << "Name" 
 << setw(10) << "Marks" << endl;
 cout << setfill('-') << setw(35) << "" << endl;

 // Data rows
 cout << setfill(' ') << left
 << setw(10) << 101 
 << setw(15) << "Alice" 
 << setw(10) << right << 95.5 << endl;

 cout << setfill(' ') << left
 << setw(10) << 102
 << setw(15) << "Bob"
 << setw(10) << right << 87.25 << endl;

 cout << setfill('=') << setw(35) << "" << endl;

 return 0;
}

#include <iostream>
#include <iomanip>
using namespace std;

int main() {
 bool flag = true;

 // Default (numeric)
 cout << "Default: " << flag << endl;

 // Boolean alpha (text)
 cout << boolalpha << flag << endl;
 cout << "Boolalpha: " << flag << endl;

 // Reset to numeric
 cout << noboolalpha << flag << endl;

 // Multiple values
 cout << boolalpha << true << " and " << false << endl;

 return 0;
}

#include <iostream>
#include <ios>
using namespace std;

int main() {
 cout << 123.456 << endl;

 // Set specific flags
 cout.setf(ios::fixed);
 cout << 123.456 << endl;

 // Clear fixed, set scientific
 cout.unsetf(ios::fixed);
 cout.setf(ios::scientific);
 cout << 123.456 << endl;

 // Reset all flags
 cout.flags(0); // Reset to default
 cout << 123.456 << endl;

 // Set multiple flags at once
 cout.setf(ios::left | ios::showpos);
 cout << 42 << endl;

 return 0;
}
